public class KthLargestElementBST {
    static int counter = 0, node = 0;

    static int kthLargest(TreeNode root, int k) {
        counter = k;
        inOrder(root);
        return node;
    }

    static void inOrder(TreeNode root) {
        if (root.right != null) {
            inOrder(root.right);
        }

        counter--;
        if (counter == 0) {
            node = root.data;
            return;
        }

        if (root.left != null) {
            inOrder(root.left);
        }
    }

    static TreeNode createBST(TreeNode root, int val) {
        if (root == null) {
            return new TreeNode(val);
        }
        if (val < root.data) {
            root.left = createBST(root.left, val);
        } else {
            root.right = createBST(root.right, val);
        }
        return root;
    }

    public static void main(String args[]) {
        int arr[] = { 10, 20, 30, 40, 50 };
        int arrSize = arr.length;

        TreeNode root = null;

        for (int i = 0; i < arrSize; i++) {
            root = createBST(root, arr[i]);
        }

        int k = 2;

        int kthSmallestEle = kthLargest(root, k);
        System.out.println("Kth Largest element is " + kthSmallestEle);
    }
}

