def successor(curr):
    succ = curr.right
    while (succ.left != None and
           succ.left != curr):
        succ = succ.left
    return succ

def returnKLargestUsingMorrisTraversal(root, k):
    if not root:
        return root

    curr = root
    out, count = None, 0
    while (curr != None):
        if (curr.right == None):
            count += 1
            if count == k:
                out = curr
            curr = curr.left
        else:
            successorNode = successor(curr)
            if (successorNode.left == None):
                successorNode.left = curr
                curr = curr.right
            else:
                successorNode.left = None
                count += 1
                if count == k:
                    out = curr
                curr = curr.left
    return out.val

